import {{ Injectable }} from '@nestjs/common';
import {{ SubscriptionService }} from './models/subscription.model';
import {{ SubscriptionServiceRepository }} from './repositories/subscription.repository';

@Injectable()
export class SubscriptionServiceService {{
  constructor(
    private readonly repository: SubscriptionServiceRepository,
  ) {{}}

  async findAll(): Promise<SubscriptionService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<SubscriptionService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<SubscriptionService>): Promise<SubscriptionService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<SubscriptionService>): Promise<SubscriptionService> {{
    return this.repository.update(id, data);
  }}
}}

